```python
# EVOLVE-BLOCK-START
"""Circle packing: 26 circles, hex lattice init + multi-restart SLSQP with perturbation + polish."""
import numpy as np
from scipy.optimize import minimize


def construct_packing():
    n = 26
    sqrt3 = np.sqrt(3.0)
    r_max = 1.0 / (2.0 + 5.0 * sqrt3)

    centers = []
    for i in range(6):
        if i % 2 == 0:
            xs = [r_max + j * 2.0 * r_max for j in range(5)]
        else:
            xs = [2.0 * r_max + j * 2.0 * r_max for j in range(4)]
        y = r_max + i * r_max * sqrt3
        for x in xs:
            centers.append([x, y])
    centers = np.array(centers[:n])
    radii = np.full(n, r_max)

    base_x0 = np.concatenate([centers[:, 0], centers[:, 1], radii])

    def neg_sum(x):
        return -np.sum(x[2*n:])

    def neg_sum_grad(x):
        g = np.zeros_like(x); g[2*n:] = -1.0; return g

    cons = []
    for i in range(n):
        cons.append({'type': 'ineq', 'fun': lambda x, i=i: x[i] - x[2*n + i]})
        cons.append({'type': 'ineq', 'fun': lambda x, i=i: 1.0 - x[i] - x[2*n + i]})
        cons.append({'type': 'ineq', 'fun': lambda x, i=i: x[n+i] - x[2*n + i]})
        cons.append({'type': 'ineq', 'fun': lambda x, i=i: 1.0 - x[n+i] - x[2*n + i]})
    for i in range(n):
        for j in range(i+1, n):
            def pair(x, i=i, j=j):
                dx = x[i] - x[j]; dy = x[n+i] - x[n+j]
                return np.sqrt(dx*dx + dy*dy) - (x[2*n+i] + x[2*n+j])
            cons.append({'type': 'ineq', 'fun': pair})

    bounds = [(0, 1)] * (2*n) + [(1e-6, 0.5)] * n

    def validate(cx, cy, rr_s):
        for i in range(n):
            if cx[i] < rr_s[i] or cx[i] > 1 - rr_s[i] or cy[i] < rr_s[i] or cy[i] > 1 - rr_s[i]:
                return False
        for i in range(n):
            for j in range(i+1, n):
                if np.hypot(cx[i]-cx[j], cy[i]-cy[j]) < rr_s[i] + rr_s[j]:
                    return False
        return True

    def try_start(x0):
        try:
            res = minimize(neg_sum, x0, jac=neg_sum_grad, method='SLSQP',
                           bounds=bounds, constraints=cons,
                           options={'maxiter': 500, 'ftol': 1e-11})
            cx, cy, rr = res.x[:n], res.x[n:2*n], res.x[2*n:]
            rr_s = rr * (1.0 - 1e-7)
            if validate(cx, cy, rr_s):
                return (cx, cy, rr_s, float(np.sum(rr_s)), res.x.copy())
        except Exception:
            pass
        return None

    best_sum = -1.0
    best_result = None
    best_x = None
    rng = np.random.default_rng(0)

    # Phase 1: restarts from hex lattice with varying perturbation scales
    starts = [base_x0]
    for scale in [0.005, 0.015, 0.03, 0.05, 0.08, 0.12]:
        pert = base_x0.copy()
        pert[:2*n] = base_x0[:2*n] + rng.normal(0, scale, 2*n)
        pert[:2*n] = np.clip(pert[:2*n], r_max*0.5, 1.0 - r_max*0.5)
        pert[2*n:] = r_max * 0.9
        starts.append(pert)

    for x0 in starts:
        out = try_start(x0)
        if out is not None:
            cx, cy, rr_s, s, fx = out
            if s > best_sum:
                best_sum = s
                best_result = (np.column_stack([cx, cy]).copy(), rr_s.copy(), s)
                best_x = fx

    # Phase 2: polish — perturb around the current best and re-optimize (multi-pass)
    polish_rounds = [
        [0.003, 0.008, 0.015, 0.025, 0.04],
        [0.001, 0.003, 0.007, 0.012, 0.02],
        [0.0005, 0.002, 0.005, 0.01],
    ]
    for scales in polish_rounds:
        if best_x is None:
            break
        improved = False
        for scale in scales:
            pert = best_x.copy()
            pert[:2*n] = best_x[:2*n] + rng.normal(0, scale, 2*n)
            pert[:2*n] = np.clip(pert[:2*n], 1e-4, 1.0 - 1e-4)
            pert[2*n:] = np.clip(best_x[2*n:] * 0.97, 1e-6, 0.5)
            out = try_start(pert)
            if out is not None:
                cx, cy, rr_s, s, fx = out
                if s > best_sum:
                    best_sum = s
                    best_result = (np.column_stack([cx, cy]).copy(), rr_s.copy(), s)
                    best_x = fx
                    improved = True
        if not improved:
            out = try_start(best_x.copy())
            if out is not None:
                cx, cy, rr_s, s, fx = out
                if s > best_sum:
                    best_sum = s
                    best_result = (np.column_stack([cx, cy]).copy(), rr_s.copy(), s)
                    best_x = fx


    # Phase 3: targeted polish on smallest circles only
    if best_x is not None:
        r_arr = best_x[2*n:]
        order = np.argsort(r_arr)
        small_idx = order[:10]
        for scale in [0.005, 0.015, 0.03, 0.05]:
            pert = best_x.copy()
            mask = np.zeros(n, dtype=bool); mask[small_idx] = True
            pert[:n][mask] = best_x[:n][mask] + rng.normal(0, scale, mask.sum())
            pert[n:2*n][mask] = best_x[n:2*n][mask] + rng.normal(0, scale, mask.sum())
            pert[:2*n] = np.clip(pert[:2*n], 1e-4, 1.0 - 1e-4)
            pert[2*n:] = np.clip(best_x[2*n:] * 0.95, 1e-6, 0.5)
            out = try_start(pert)
            if out is not None:
                cx, cy, rr_s, s, fx = out
                if s > best_sum:
                    best_sum = s
                    best_result = (np.column_stack([cx, cy]).copy(), rr_s.copy(), s)
                    best_x = fx

    if best_result is not None and best_sum > n * r_max * (1.0 - 1e-7):
        return best_result

    r = r_max * (1.0 - 1e-7)
    return centers, np.full(n, r), float(n * r)
# EVOLVE-BLOCK-END


def run_packing():
    return construct_packing()


if __name__ == "__main__":
    centers, radii, sum_radii = run_packing()
    print(f"Sum of radii: {sum_radii:.6f}")

```
